svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var hitLayer = document.getElementById('hit-layer');
    var tipLayer = document.getElementById('tip-layer');
    var legendRoot = document.getElementById('legend-root');
    var SERIES_REVEAL_DURATION = 0.8;
    var seriesGroups = [];

    var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct'];
    var series = [
      { id: 1, name: 'Engineering', ci: 1, values: [95, 95, 110, 110, 128, 128, 155, 155, 182, 182] },
      { id: 2, name: 'Data & ML', ci: 2, values: [60, 72, 72, 88, 88, 105, 105, 120, 143, 143] },
      { id: 3, name: 'Product', ci: 3, values: [38, 38, 45, 45, 52, 52, 60, 60, 67, 67] },
      { id: 4, name: 'Marketing', ci: 4, values: [28, 28, 32, 32, 38, 38, 40, 44, 44, 44] }
    ];

    var plotL = 68;
    var plotR = 832;
    var plotT = 100;
    var plotB = 500;
    var n = months.length;
    var step = (plotR - plotL) / (n - 1);
    var hitHalfWidth = step / 2;
    var yMin = 0;
    var yMax = 200;
    var totals = months.map(function (_, index) {
      return series.reduce(function (sum, entry) {
        return sum + entry.values[index];
      }, 0);
    });

    function xAt(i) { return plotL + i * step; }
    function yAt(v) { return plotB - (v - yMin) / (yMax - yMin) * (plotB - plotT); }
    function areaPath(values) {
      var d = 'M' + xAt(0) + ',' + yAt(values[0]);
      for (var i = 1; i < values.length; i += 1) d += ' H' + xAt(i) + ' V' + yAt(values[i]);
      d += ' V' + plotB + ' H' + xAt(0) + ' Z';
      return d;
    }
    function strokePath(values) {
      var d = 'M' + xAt(0) + ',' + yAt(values[0]);
      for (var i = 1; i < values.length; i += 1) d += ' H' + xAt(i) + ' V' + yAt(values[i]);
      return d;
    }
    function setSeriesActive(qi, mouseY) {
      var bestSid = ctx.getNearestSeriesIdAtColumn(series.map(function (entry) {
        return {
          id: entry.id,
          ys: entry.values.map(function (value) { return yAt(value); })
        };
      }), qi, mouseY);
      ctx.setSeriesHoverState({
        hoverLayer: dataLayerEl,
        hovering: true,
        activeSid: bestSid,
        seriesIds: series.map(function (entry) { return entry.id; }),
        lineSelector: '#sg-{id}'
      });
    }
    function clearSeriesActive() {
      ctx.setSeriesHoverState({
        hoverLayer: dataLayerEl,
        hovering: false,
        activeSid: null,
        seriesIds: series.map(function (entry) { return entry.id; }),
        lineSelector: '#sg-{id}'
      });
    }

    series.forEach(function (entry, seriesIndex) {
      var sg = ctx.el('g', {
        id: 'sg-' + entry.id,
        'class': 'sg',
        'data-series-id': String(entry.id),
        'data-series-index': String(seriesIndex)
      });
      var fill = ctx.el('path', {
        'class': 'area-fill series-' + entry.ci,
        d: areaPath(entry.values),
        'fill-opacity': '0.18',
        stroke: 'none'
      });
      var stroke = ctx.el('path', {
        'class': 'area-stroke series-' + entry.ci + ' use-series-stroke',
        d: strokePath(entry.values)
      });

      sg.appendChild(fill);
      sg.appendChild(stroke);

      dataLayerEl.appendChild(sg);
      seriesGroups.push(sg);
    });

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      rowGap: 48,
      items: series.map(function (entry) {
        return {
          label: entry.name,
          value: '$' + entry.values[entry.values.length - 1] + 'k',
          cls: 'series-' + entry.ci
        };
      })
    });

    ctx.initRevealSequence(seriesGroups, {
      animationName: 'fadeIn',
      duration: SERIES_REVEAL_DURATION,
      easing: 'ease-out',
      delays: seriesGroups.map(function (_, index) {
        return ctx.getStaggerDelay(index, seriesGroups.length, 1.0);
      })
    });

    ctx.initStackedSummaryTooltip({
      xs: months.map(function (_, index) { return xAt(index); }),
      quarters: months,
      series: series.map(function (entry) {
        return {
          id: entry.id,
          cls: 'series-' + entry.ci,
          label: entry.name,
          vals: entry.values,
          ys: entry.values.map(function (value) { return yAt(value); })
        };
      }),
      totals: totals,
      tipLayer: tipLayer,
      hitLayer: hitLayer,
      plotL: plotL,
      plotR: plotR,
      plotT: plotT,
      plotB: plotB,
      anchorY: (plotT + plotB) / 2,
      hitTop: plotT,
      hitHeight: plotB - plotT,
      hitHalfWidth: hitHalfWidth,
      hitMinX: plotL,
      hitMaxX: plotR,
      hitIdPrefix: 'hit-',
      onEnter: function (qi, sp, tipG, ch) {
        setSeriesActive(qi, sp.y);
        ctx.setOpacity(tipG, 1);
        ctx.setOpacity(ch, 1);
      },
      onMove: function (qi, sp) {
        setSeriesActive(qi, sp.y);
      },
      onLeave: function (qi, tipG, ch) {
        clearSeriesActive();
        ctx.setOpacity(tipG, null);
        ctx.setOpacity(ch, null);
      }
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: seriesGroups.map(function (_, index) {
        return ctx.getStaggerDelay(index, seriesGroups.length, 1.0);
      }),
      duration: SERIES_REVEAL_DURATION,
      buffer: 0.1
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
